DROP TABLE IF EXISTS `contract_attachment_ocr`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `contract_attachment_ocr` (
  `ocr_id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT 'OCR结果ID',
  `attachment_id` bigint unsigned NOT NULL COMMENT '附件ID',
  `ocr_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL DEFAULT 'PENDING' COMMENT 'OCR状态：PENDING待识别/RUNNING识别中/SUCCESS成功/FAILED失败',
  `preview_html` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin COMMENT '坐标原样还原HTML，用于页面预览',
  `editor_html` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin COMMENT 'OCR???????????HTML',
  `editor_html_source` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT 'rule_layout' COMMENT '???HTML???rule_layout/ai_structured_layout',
  `editor_html_model` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'AI??????',
  `editor_html_duration_ms` bigint DEFAULT NULL COMMENT 'AI????????',
  `plain_text` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin COMMENT 'OCR纯文本，用于复制、检索和AI分析',
  `ocr_blocks_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin COMMENT 'OCR结构化块JSON，包含page、bbox、text等信息',
  `ocr_raw_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin COMMENT 'OCR原始返回JSON',
  `qwen_layout_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin COMMENT '千问版面分析JSON',
  `parse_source` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '解析来源：PADDLE/QWEN/FALLBACK/MANUAL',
  `approximate` tinyint unsigned NOT NULL DEFAULT '0' COMMENT '是否为近似还原：0否，1是',
  `parse_warnings` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin COMMENT '解析警告JSON',
  `page_count` int unsigned DEFAULT NULL COMMENT '页数',
  `ocr_model` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'OCR模型名称',
  `qwen_model` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '千问模型名称',
  `ocr_duration_ms` bigint unsigned DEFAULT NULL COMMENT 'OCR耗时毫秒',
  `qwen_duration_ms` bigint unsigned DEFAULT NULL COMMENT '千问处理耗时毫秒',
  `ocr_error` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'OCR失败原因',
  `created_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT 'SYSTEM_INIT' COMMENT '创建人',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '更新人',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `is_deleted` tinyint unsigned NOT NULL DEFAULT '0' COMMENT '逻辑删除：0未删除，1已删除',
  `version` int unsigned NOT NULL DEFAULT '1' COMMENT '乐观锁版本号',
  PRIMARY KEY (`ocr_id`),
  UNIQUE KEY `uk_attachment_id` (`attachment_id`),
  KEY `idx_attachment_id` (`attachment_id`),
  KEY `idx_ocr_status` (`ocr_status`),
  KEY `idx_parse_source` (`parse_source`),
  CONSTRAINT `fk_attachment_ocr_attachment` FOREIGN KEY (`attachment_id`) REFERENCES `contract_attachment` (`attachment_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=89 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin COMMENT='合同附件OCR结果表';
/*!40101 SET character_set_client = @saved_cs_client */;

